import{_ as e,o,c as a,a7 as n}from"./chunks/framework.C4ZIv4ii.js";const m=JSON.parse('{"title":"Containers & Columns","description":"","frontmatter":{},"headers":[],"relativePath":"builder/containers.md","filePath":"builder/containers.md","lastUpdated":1781554731000}'),i={name:"builder/containers.md"};function l(r,t,s,d,c,h){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="containers-columns" tabindex="-1">Containers &amp; Columns <a class="header-anchor" href="#containers-columns" aria-label="Permalink to &quot;Containers &amp; Columns&quot;">​</a></h1><p>Every Falcon Builder layout starts with Containers, which hold Columns, which hold Elements.</p><h2 id="containers" tabindex="-1">Containers <a class="header-anchor" href="#containers" aria-label="Permalink to &quot;Containers&quot;">​</a></h2><p>A container is a full-width row on your page. Click <strong>+ Add Container</strong> to open the Column Select modal.</p><h3 id="container-settings" tabindex="-1">Container Settings <a class="header-anchor" href="#container-settings" aria-label="Permalink to &quot;Container Settings&quot;">​</a></h3><p>Right-click the container toolbar or click the gear icon:</p><p><strong>Layout:</strong></p><ul><li>Background color, gradient, or image</li><li>Background position and size</li><li>Min height</li><li>Padding (top, right, bottom, left)</li><li>Margin</li></ul><p><strong>Advanced:</strong></p><ul><li>CSS Class, CSS ID</li><li>Custom CSS</li><li>Animation on scroll (fade in, slide up, zoom)</li><li>Sticky (sticks to top on scroll)</li></ul><p><strong>Visibility:</strong></p><ul><li>Show/hide on Desktop, Tablet, Mobile</li></ul><h3 id="container-toolbar-actions" tabindex="-1">Container Toolbar Actions <a class="header-anchor" href="#container-toolbar-actions" aria-label="Permalink to &quot;Container Toolbar Actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Icon</th><th>Action</th></tr></thead><tbody><tr><td>↕</td><td>Drag to reorder the container</td></tr><tr><td>✏️</td><td>Edit container settings</td></tr><tr><td>📋</td><td>Duplicate container</td></tr><tr><td>📚</td><td>Save to Library</td></tr><tr><td>🌐</td><td>Save as Global Section</td></tr><tr><td>🗑️</td><td>Delete container</td></tr></tbody></table><hr><h2 id="column-layouts" tabindex="-1">Column Layouts <a class="header-anchor" href="#column-layouts" aria-label="Permalink to &quot;Column Layouts&quot;">​</a></h2><p>When adding a container, choose from preset column layouts:</p><table tabindex="0"><thead><tr><th>Layout</th><th>Description</th></tr></thead><tbody><tr><td><code>1/1</code></td><td>Single full-width column</td></tr><tr><td><code>1/2 + 1/2</code></td><td>Two equal columns</td></tr><tr><td><code>1/3 + 2/3</code></td><td>Narrow + wide</td></tr><tr><td><code>2/3 + 1/3</code></td><td>Wide + narrow</td></tr><tr><td><code>1/3 + 1/3 + 1/3</code></td><td>Three equal columns</td></tr><tr><td><code>1/4 + 3/4</code></td><td>Sidebar + main</td></tr><tr><td><code>1/4 + 1/4 + 1/4 + 1/4</code></td><td>Four equal columns</td></tr></tbody></table><p>More layouts are available in the modal. Custom ratios can be set in column settings.</p><hr><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><p>Each column inside a container holds one or more elements.</p><h3 id="column-settings" tabindex="-1">Column Settings <a class="header-anchor" href="#column-settings" aria-label="Permalink to &quot;Column Settings&quot;">​</a></h3><p>Click the column toolbar:</p><p><strong>Size:</strong></p><ul><li>Width percentage (responsive: desktop, tablet, mobile)</li><li>Padding</li></ul><p><strong>Background:</strong></p><ul><li>Background color or image</li></ul><p><strong>Vertical Align:</strong></p><ul><li>Top, Middle, Bottom, Stretch</li></ul><p><strong>Advanced:</strong></p><ul><li>CSS Class, CSS ID</li><li>Custom CSS</li></ul><h3 id="responsive-column-widths" tabindex="-1">Responsive Column Widths <a class="header-anchor" href="#responsive-column-widths" aria-label="Permalink to &quot;Responsive Column Widths&quot;">​</a></h3><p>Each column can have different widths per device:</p><table tabindex="0"><thead><tr><th>Device</th><th>Example</th></tr></thead><tbody><tr><td>Desktop</td><td>1/3 (33%)</td></tr><tr><td>Tablet</td><td>1/2 (50%)</td></tr><tr><td>Mobile</td><td>1/1 (100%)</td></tr></tbody></table><p>This makes your layout naturally stack on mobile.</p><hr><h2 id="adding-elements-to-columns" tabindex="-1">Adding Elements to Columns <a class="header-anchor" href="#adding-elements-to-columns" aria-label="Permalink to &quot;Adding Elements to Columns&quot;">​</a></h2><p>Click the <strong>+</strong> button inside a column to open the Element Select modal. Choose an element type and it&#39;s inserted into the column.</p><p>Elements can be dragged within a column or between columns.</p><hr><h2 id="responsive-preview" tabindex="-1">Responsive Preview <a class="header-anchor" href="#responsive-preview" aria-label="Permalink to &quot;Responsive Preview&quot;">​</a></h2><p>Use the device buttons at the top of the builder to preview your layout on:</p><ul><li>🖥 Desktop</li><li>📱 Tablet</li><li>📲 Mobile</li></ul><p>The canvas resizes and shows how the layout looks on each device.</p><hr><h2 id="saving-publishing" tabindex="-1">Saving &amp; Publishing <a class="header-anchor" href="#saving-publishing" aria-label="Permalink to &quot;Saving &amp; Publishing&quot;">​</a></h2><ul><li><strong>Autosave</strong> runs every 30 seconds — your work is never lost</li><li>Click <strong>Save Draft</strong> to save without publishing</li><li>Click <strong>Publish / Update</strong> to make changes live</li><li>View <strong>Revisions</strong> to restore any previous version</li></ul>',48)])])}const p=e(i,[["render",l]]);export{m as __pageData,p as default};
